5849 /// Match and fold patterns like:
5850 ///   icmp eq/ne X, min(max(X, Lo), Hi)
5851 /// which represents a range check and can be repsented as a ConstantRange.
5852 ///
5853 /// For icmp eq, build ConstantRange [Lo, Hi + 1) and convert to:
5854 ///   (X - Lo) u< (Hi + 1 - Lo)
5855 /// For icmp ne, build ConstantRange [Hi + 1, Lo) and convert to:
5856 ///   (X - (Hi + 1)) u< (Lo - (Hi + 1))
5857 Instruction *InstCombinerImpl::foldICmpWithClamp(ICmpInst &I, Value *X,
5858                                                  MinMaxIntrinsic *Min) {
5859   if (!I.isEquality() || !Min->hasOneUse() || !Min->isMin())
5860     return nullptr;
5861 
5862   const APInt *Lo = nullptr, *Hi = nullptr;
5863   if (Min->isSigned()) {
5864     if (!match(Min->getLHS(), m_OneUse(m_SMax(m_Specific(X), m_APInt(Lo)))) ||
5865         !match(Min->getRHS(), m_APInt(Hi)) || !Lo->slt(*Hi))
5866       return nullptr;
5867   } else {
5868     if (!match(Min->getLHS(), m_OneUse(m_UMax(m_Specific(X), m_APInt(Lo)))) ||
5869         !match(Min->getRHS(), m_APInt(Hi)) || !Lo->ult(*Hi))
5870       return nullptr;
5871   }
5872 
5873   ConstantRange CR = ConstantRange::getNonEmpty(*Lo, *Hi + 1);
5874   ICmpInst::Predicate Pred;
5875   APInt C, Offset;
5876   if (I.getPredicate() == ICmpInst::ICMP_EQ)
5877     CR.getEquivalentICmp(Pred, C, Offset);
5878   else
5879     CR.inverse().getEquivalentICmp(Pred, C, Offset);
5880 
5881   if (!Offset.isZero())
5882     X = Builder.CreateAdd(X, ConstantInt::get(X->getType(), Offset));
5883 
5884   return replaceInstUsesWith(
5885       I, Builder.CreateICmp(Pred, X, ConstantInt::get(X->getType(), C)));
5886 }
