7544 /// This function folds patterns produced by lowering of reduce idioms, such as
7545 /// llvm.vector.reduce.and which are lowered into instruction chains. This code
7546 /// attempts to generate fewer number of scalar comparisons instead of vector
7547 /// comparisons when possible.
7548 static Instruction *foldReductionIdiom(ICmpInst &I,
7549                                        InstCombiner::BuilderTy &Builder,
7550                                        const DataLayout &DL) {
7551   if (I.getType()->isVectorTy())
7552     return nullptr;
7553   CmpPredicate OuterPred, InnerPred;
7554   Value *LHS, *RHS;
7555 
7556   // Match lowering of @llvm.vector.reduce.and. Turn
7557   ///   %vec_ne = icmp ne <8 x i8> %lhs, %rhs
7558   ///   %scalar_ne = bitcast <8 x i1> %vec_ne to i8
7559   ///   %res = icmp <pred> i8 %scalar_ne, 0
7560   ///
7561   /// into
7562   ///
7563   ///   %lhs.scalar = bitcast <8 x i8> %lhs to i64
7564   ///   %rhs.scalar = bitcast <8 x i8> %rhs to i64
7565   ///   %res = icmp <pred> i64 %lhs.scalar, %rhs.scalar
7566   ///
7567   /// for <pred> in {ne, eq}.
7568   if (!match(&I, m_ICmp(OuterPred,
7569                         m_OneUse(m_BitCast(m_OneUse(
7570                             m_ICmp(InnerPred, m_Value(LHS), m_Value(RHS))))),
7571                         m_Zero())))
7572     return nullptr;
7573   auto *LHSTy = dyn_cast<FixedVectorType>(LHS->getType());
7574   if (!LHSTy || !LHSTy->getElementType()->isIntegerTy())
7575     return nullptr;
7576   unsigned NumBits =
7577       LHSTy->getNumElements() * LHSTy->getElementType()->getIntegerBitWidth();
7578   // TODO: Relax this to "not wider than max legal integer type"?
7579   if (!DL.isLegalInteger(NumBits))
7580     return nullptr;
7581 
7582   if (ICmpInst::isEquality(OuterPred) && InnerPred == ICmpInst::ICMP_NE) {
7583     auto *ScalarTy = Builder.getIntNTy(NumBits);
7584     LHS = Builder.CreateBitCast(LHS, ScalarTy, LHS->getName() + ".scalar");
7585     RHS = Builder.CreateBitCast(RHS, ScalarTy, RHS->getName() + ".scalar");
7586     return ICmpInst::Create(Instruction::ICmp, OuterPred, LHS, RHS,
7587                             I.getName());
7588   }
7589 
7590   return nullptr;
7591 }
