7710 Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
7711   bool Changed = false;
7712   const SimplifyQuery Q = SQ.getWithInstruction(&I);
7713   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
7714   unsigned Op0Cplxity = getComplexity(Op0);
7715   unsigned Op1Cplxity = getComplexity(Op1);
7716 
7717   /// Orders the operands of the compare so that they are listed from most
7718   /// complex to least complex.  This puts constants before unary operators,
7719   /// before binary operators.
7720   if (Op0Cplxity < Op1Cplxity) {
7721     I.swapOperands();
7722     std::swap(Op0, Op1);
7723     Changed = true;
7724   }
7725 
7726   if (Value *V = simplifyICmpInst(I.getCmpPredicate(), Op0, Op1, Q))
7727     return replaceInstUsesWith(I, V);
7728 
7729   // Comparing -val or val with non-zero is the same as just comparing val
7730   // ie, abs(val) != 0 -> val != 0
7731   if (I.getPredicate() == ICmpInst::ICMP_NE && match(Op1, m_Zero())) {
7732     Value *Cond, *SelectTrue, *SelectFalse;
7733     if (match(Op0, m_Select(m_Value(Cond), m_Value(SelectTrue),
7734                             m_Value(SelectFalse)))) {
7735       if (Value *V = dyn_castNegVal(SelectTrue)) {
7736         if (V == SelectFalse)
7737           return CmpInst::Create(Instruction::ICmp, I.getPredicate(), V, Op1);
7738       } else if (Value *V = dyn_castNegVal(SelectFalse)) {
7739         if (V == SelectTrue)
7740           return CmpInst::Create(Instruction::ICmp, I.getPredicate(), V, Op1);
7741       }
7742     }
7743   }
7744 
7745   if (Instruction *Res = foldICmpTruncWithTruncOrExt(I, Q))
7746     return Res;
7747 
7748   if (Op0->getType()->isIntOrIntVectorTy(1))
7749     if (Instruction *Res = canonicalizeICmpBool(I, Builder))
7750       return Res;
7751 
7752   if (Instruction *Res = canonicalizeCmpWithConstant(I))
7753     return Res;
7754 
7755   if (Instruction *Res = canonicalizeICmpPredicate(I))
7756     return Res;
7757 
7758   if (Instruction *Res = foldICmpWithConstant(I))
7759     return Res;
7760 
7761   if (Instruction *Res = foldICmpWithDominatingICmp(I))
7762     return Res;
7763 
7764   if (Instruction *Res = foldICmpUsingBoolRange(I))
7765     return Res;
7766 
7767   if (Instruction *Res = foldICmpUsingKnownBits(I))
7768     return Res;
7769 
7770   if (Instruction *Res = foldIsMultipleOfAPowerOfTwo(I))
7771     return Res;
7772 
7773   // Test if the ICmpInst instruction is used exclusively by a select as
7774   // part of a minimum or maximum operation. If so, refrain from doing
7775   // any other folding. This helps out other analyses which understand
7776   // non-obfuscated minimum and maximum idioms, such as ScalarEvolution
7777   // and CodeGen. And in this case, at least one of the comparison
7778   // operands has at least one user besides the compare (the select),
7779   // which would often largely negate the benefit of folding anyway.
7780   //
7781   // Do the same for the other patterns recognized by matchSelectPattern.
7782   if (I.hasOneUse())
7783     if (SelectInst *SI = dyn_cast<SelectInst>(I.user_back())) {
7784       Value *A, *B;
7785       SelectPatternResult SPR = matchSelectPattern(SI, A, B);
7786       if (SPR.Flavor != SPF_UNKNOWN)
7787         return nullptr;
7788     }
